// -- DESK ------------------------------------------------------------
// A little desk buzzer that fires a message across to the Waveshare
// ESP32-C6-LCD board. Each press cycles to the next canned message,
// sends it to the board named "display", and the LED + buzzer confirm
// it left the desk. Both boards must be connected -- switch tabs (or use
// the IDE board picker) to watch the screen fill up.
//
// You are `send_btn`; `sent_led` and `buzzer` are wired beside you.

fn on_start() {
    this.msgs = ["hello!", "coffee?", "on my way", "lunch @ 12", "ping"];
    this.i = -1;
    rgb(0, 0, 20);
    log("press to send a message to the LCD board");
}

fn on_press() {
    this.i = (this.i + 1) % this.msgs.len();
    let text = this.msgs[this.i];
    send_board("display", text);        // "*" would broadcast to every board
    log(`sent: ${text}`);

    // Confirm the send: blip the LED and chirp the buzzer.
    sent_led.on();
    buzzer.beep(120);
    after(150, || sent_led.off());
}

fn on_board_msg(from, text) {
    if text == "shown" {                // the display acknowledged it
        rgb(0, 40, 0);
        after(400, || rgb(0, 0, 20));
    }
}

// -- DISPLAY ---------------------------------------------------------
// The Waveshare ESP32-C6-LCD-1.47: a 172x320 ST7789 screen wired to the
// chip on-board (MOSI 6, SCLK 7, CS 14, DC 15, RST 21) -- no jumpers, the
// panel is soldered on. It receives messages from the "desk" board over
// send_board, prints the latest one, keeps a running count and flashes
// its RGB LED. The simulator renders the display on this component.

fn repaint(count, from, text) {
    lcd_clear(6, 8, 20);
    lcd_rect(0, 0, 128, 16, 20, 40, 90);
    lcd_text(6, 4, "MESSAGES", 235, 240, 255);
    lcd_text(92, 4, `#${count}`, 180, 200, 255);
    if text != "" {
        lcd_rect(6, 30, 116, 22, 20, 24, 44);
        lcd_text(10, 36, text, 255, 235, 120);
        lcd_text(10, 60, `from ${from}`, 150, 170, 210);
    } else {
        lcd_text(10, 40, "waiting...", 120, 140, 170);
    }
}

fn on_start() {
    lcd_init(6, 7, 14, 15, 21);         // the Waveshare on-board mapping
    this.count = 0;
    repaint(0, "", "");
    rgb(0, 8, 0);
    log(`inbox ready on ${chip()}`);
}

fn on_board_msg(from, text) {
    this.count += 1;
    repaint(this.count, from, text);
    rgb(0, 45, 10);                     // flash on receive
    after(250, || rgb(0, 8, 0));
    send_board(from, "shown");          // acknowledge the sender
    log(`#${this.count} from ${from}: ${text}`);
}
